	@Test
	void parsesVersionedTreeAndEstablishesParentLinks() throws Exception {
		TupleExpr parsed = parser.parse("""
				{
				  "format": "rdf4j-tuple-expr",
				  "version": 1,
				  "expression": {
				    "type": "Projection",
				    "subquery": false,
				    "arg": {
				      "type": "Filter",
				      "arg": {
				        "type": "Join",
				        "mergeJoin": true,
				        "resultSizeEstimate": 2.5,
				        "leftArg": {
				          "type": "StatementPattern",
				          "scope": "NAMED_CONTEXTS",
				          "subjectVar": { "type": "Var", "name": "s" },
				          "predicateVar": {
				            "type": "Var",
				            "name": "p",
				            "value": { "type": "IRI", "value": "urn:test:p" },
				            "constant": true
				          },
				          "objectVar": { "type": "Var", "name": "o" },
				          "contextVar": { "type": "Var", "name": "g" },
				          "statementOrder": "S",
				          "indexName": "spoc"
				        },
				        "rightArg": {
				          "type": "BindingSetAssignment",
				          "declaredBindingNames": ["o", "label"],
				          "bindingSets": [
				            {
				              "o": { "type": "IRI", "value": "urn:test:o" },
				              "label": {
				                "type": "Literal",
				                "label": "hello",
				                "language": "en",
				                "direction": "rtl"
				              }
				            },
				            { "o": null }
				          ]
				        }
				      },
				      "condition": {
				        "type": "Compare",
				        "operator": "=",
				        "leftArg": { "type": "Var", "name": "o" },
				        "rightArg": {
				          "type": "ValueConstant",
				          "value": { "type": "IRI", "value": "urn:test:o" }
				        }
				      }
				    },
				    "projectionElements": [
				      { "name": "s" },
				      { "name": "label", "projectionAlias": "text" }
				    ]
				  }
				}
				""");

		Projection projection = assertInstanceOf(Projection.class, parsed);
		assertFalse(projection.isSubquery());
		assertEquals("text",
				projection.getProjectionElemList().getElements().get(1).getProjectionAlias().orElseThrow());

		Filter filter = assertInstanceOf(Filter.class, projection.getArg());
		assertSame(projection, filter.getParentNode());
		assertSame(filter, filter.getCondition().getParentNode());

		Join join = assertInstanceOf(Join.class, filter.getArg());
		assertTrue(join.isMergeJoin());
		assertEquals(2.5d, join.getResultSizeEstimate());
		assertSame(filter, join.getParentNode());

		StatementPattern statementPattern = assertInstanceOf(StatementPattern.class, join.getLeftArg());
		assertEquals(StatementPattern.Scope.NAMED_CONTEXTS, statementPattern.getScope());
		assertEquals("spoc", statementPattern.getIndexName());
		assertSame(statementPattern, statementPattern.getSubjectVar().getParentNode());
		assertEquals("urn:test:p", statementPattern.getPredicateVar().getValue().stringValue());

		BindingSetAssignment assignment = assertInstanceOf(BindingSetAssignment.class, join.getRightArg());
		assertEquals(java.util.Set.of("o", "label"), assignment.getDeclaredBindingNames());
		java.util.Iterator<BindingSet> rows = assignment.getBindingSets().iterator();
		BindingSet first = rows.next();
		assertInstanceOf(IRI.class, first.getValue("o"));
		Literal label = assertInstanceOf(Literal.class, first.getValue("label"));
		assertEquals(Literal.BaseDirection.RTL, label.getBaseDirection());
		assertTrue(rows.next().isEmpty());
	}

	@Test
	void parsedNaryChildrenCanBeReplacedWithValidParentLinks() throws Exception {
		TupleExpr parsed = parser.parse(node("Extension", fields(
				"arg", node("SingletonSet", ""),
				"elements", "[{\"name\":\"term\",\"expr\":" + node("StrLangDir", fields(
						"lexicalFormArg", variable("lexical"),
						"langArg", variable("language"),
						"dirArg", variable("direction"))) + "}]")));

		Extension extension = assertInstanceOf(Extension.class, parsed);
		StrLangDir strLangDir = assertInstanceOf(StrLangDir.class, extension.getElements().get(0).getExpr());
		Var replacement = new Var("replacement");
		strLangDir.getLangArg().replaceWith(replacement);

		assertSame(replacement, strLangDir.getLangArg());
		assertSame(strLangDir, replacement.getParentNode());
	}

